import { motion } from 'framer-motion';
import { ExternalLink, Github } from 'lucide-react';

interface ProjectCardProps {
  title: string;
  description: string;
  image: string;
  link?: string;
  repo?: string;
  tech: string[];
}

export function ProjectCard({ title, description, image, link, repo, tech }: ProjectCardProps) {
  return (
    <motion.div 
      whileHover={{ y: -5, boxShadow: '0 0 20px rgba(0, 255, 65, 0.4)' }}
      className="bg-hacker-card rounded-xl border border-hacker-border overflow-hidden transition-all duration-300"
    >
      <div className="h-48 overflow-hidden relative group">
        <img 
          src={image} 
          alt={title} 
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-hacker-bg/50 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center space-x-4">
          {link && (
            <a href={link} target="_blank" rel="noopener noreferrer" className="p-2 bg-black/80 rounded-full hover:text-hacker-green hover:shadow-glow transition-all">
              <ExternalLink size={20} />
            </a>
          )}
          {repo && (
            <a href={repo} target="_blank" rel="noopener noreferrer" className="p-2 bg-black/80 rounded-full hover:text-hacker-green hover:shadow-glow transition-all">
              <Github size={20} />
            </a>
          )}
        </div>
      </div>
      
      <div className="p-6">
        <h3 className="text-xl font-bold text-gray-100 mb-2 font-mono group-hover:text-hacker-green transition-colors">{title}</h3>
        <p className="text-gray-400 text-sm mb-4 line-clamp-3">{description}</p>
        
        <div className="flex flex-wrap gap-2 mt-auto">
          {tech.map((t, idx) => (
            <span 
              key={idx} 
              className="text-xs px-2 py-1 rounded bg-hacker-dim text-hacker-green border border-hacker-green/30"
            >
              {t}
            </span>
          ))}
        </div>
      </div>
    </motion.div>
  );
}