import YAML from 'yaml';

export interface ProfileData {
  name: string;
  role: string;
  avatar: string;
  contact: {
    email?: string;
    github?: string;
    twitter?: string;
  };
  skills: string[];
  projects: Array<{
    title: string;
    description: string;
    image: string;
    link?: string;
    repo?: string;
    tech: string[];
  }>;
}

export function parseContent(rawContent: string): { data: ProfileData; content: string } {
  const frontMatterRegex = /^---\n([\s\S]*?)\n---\n([\s\S]*)$/;
  const match = rawContent.match(frontMatterRegex);
  
  if (!match) {
    throw new Error('Invalid markdown format. Missing frontmatter.');
  }

  const [, yamlString, markdownContent] = match;
  const data = YAML.parse(yamlString) as ProfileData;
  
  return {
    data,
    content: markdownContent.trim()
  };
}