import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';

interface TerminalProps {
  title: string;
  lines: string[];
}

export function Terminal({ title, lines }: TerminalProps) {
  const [currentLineIndex, setCurrentLineIndex] = useState(0);
  const [currentText, setCurrentText] = useState('');

  useEffect(() => {
    if (currentLineIndex >= lines.length) return;

    const fullText = lines[currentLineIndex];
    let currentIndex = 0;

    const interval = setInterval(() => {
      setCurrentText(fullText.slice(0, currentIndex + 1));
      currentIndex++;

      if (currentIndex > fullText.length) {
        clearInterval(interval);
        setTimeout(() => {
          setCurrentLineIndex(prev => prev + 1);
          setCurrentText('');
        }, 500); // Wait before next line
      }
    }, 50); // Typing speed

    return () => clearInterval(interval);
  }, [currentLineIndex, lines]);

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="w-full max-w-3xl mx-auto rounded-lg overflow-hidden bg-hacker-card border border-hacker-border shadow-glow"
    >
      {/* Terminal Header */}
      <div className="bg-[#1a1a1a] px-4 py-2 flex items-center border-b border-hacker-border rounded-t-lg">
        <div className="flex space-x-2 absolute">
          <div className="w-3 h-3 rounded-full bg-red-500"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
          <div className="w-3 h-3 rounded-full bg-green-500"></div>
        </div>
        <div className="flex-1 text-center text-xs text-gray-400 font-mono">
          {title}
        </div>
      </div>

      {/* Terminal Body */}
      <div className="p-6 font-mono text-sm md:text-base text-hacker-green min-h-[200px]">
        {lines.slice(0, currentLineIndex).map((line, i) => (
          <div key={i} className="mb-2">
            <span className="text-pink-500">➜</span> <span className="text-blue-400">~</span> {line}
          </div>
        ))}
        
        {currentLineIndex < lines.length && (
          <div className="mb-2">
            <span className="text-pink-500">➜</span> <span className="text-blue-400">~</span> {currentText}
            <motion.span 
              animate={{ opacity: [1, 0] }} 
              transition={{ repeat: Infinity, duration: 0.8 }}
              className="inline-block w-2 h-4 bg-hacker-green ml-1 align-middle"
            />
          </div>
        )}

        {currentLineIndex >= lines.length && (
          <div>
            <span className="text-pink-500">➜</span> <span className="text-blue-400">~</span> 
            <motion.span 
              animate={{ opacity: [1, 0] }} 
              transition={{ repeat: Infinity, duration: 0.8 }}
              className="inline-block w-2 h-4 bg-hacker-green ml-1 align-middle"
            />
          </div>
        )}
      </div>
    </motion.div>
  );
}