import { motion } from 'framer-motion';

export function SkillBadge({ skill, index }: { skill: string; index: number }) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.8 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true }}
      transition={{ delay: index * 0.1, type: "spring", stiffness: 260, damping: 20 }}
      whileHover={{ scale: 1.1, boxShadow: '0 0 15px rgba(0, 255, 65, 0.6)' }}
      className="flex items-center justify-center px-4 py-3 bg-hacker-card border border-hacker-border rounded-lg cursor-pointer transition-colors hover:border-hacker-green hover:bg-hacker-dim/50"
    >
      <span className="font-mono text-sm text-gray-300 font-semibold tracking-wider hover:text-white transition-colors">
        {skill}
      </span>
    </motion.div>
  );
}